# Data models module

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

class Counter:
    _value: int

    def __init__(self):
        self._value = 0

    def increment(self) -> int:
        self._value += 1
        return self._value

    def get_value(self) -> int:
        return self._value
